import { Link } from 'react-router-dom';
import React from 'react'

import classes from './Footer.module.css';

import logo from '../../Assets/stelogo.jpg';
import hrt from '../../Assets/heart.gif';
import mail from '../../Assets/gmail.png';
import insta from '../../Assets/instagram.png';
import linked from '../../Assets/linkedin.png';
import phone from '../../Assets/smartphone.png';
import loc from '../../Assets/visit.png';

export const Footer = () => {
  return (
    <div className={classes.container}>
        <div className={classes.top}>
            <div className={classes.row1}>
                <div className={classes.logo}><img src={logo} alt='Sachin tools'></img></div>
                <div className={classes.icon}></div>
            </div>
            <div className={classes.row2}>
                <h3>Extra Links</h3>
                <p>Home</p>
                <p>About</p>
                <p>Contact</p>
            </div>
            <div className={classes.row3}>
                <h3>Our Products</h3>
                <p>Corepin</p>
                <p>Total Toom Component</p>
                <p>Grinding Works</p>
                <p>Carbide Dead Centers</p>
                <p>CARBIDE AND HSS CUTTERS RESHARPENING</p>
                <p>Valve Seat Adapter</p>
                <p>Precious Component</p>
                <p>Restpad</p>
                <p>Industrialc Cutter</p>
            </div>
            <div className={classes.row4}>
                <h3>Reach Us</h3>
                <p><i class="fa-solid fa-location-dot"></i> S. NO. 38/1, KHEDEKAR INDUSTRIAL ,ESTATE, BEHIND PARI CO., NARHEGAON, PUNE -411041</p>
                <p>sachintoolsengg@gmail.com <br/> sachintoolsengg@yahoo.co.in</p>
                <p>+919850089067 <br/>+919850089065</p>
            </div>
        </div>
        <div className={classes.bottom}>
            <p>Copyright © 2023 Sachin Tools Engineering | Made with <img className={classes.heart} src={hrt} alt='Sachin tools'></img> by Cortica Web Solutions Pvt.Ltd</p>
        </div>
    </div>
    
);
};
